#[cfg(test)]
mod biber_eval_tests {
    use super::*;
    use std::collections::HashMap;

    fn tx(nonce: u64, amount: u64, fee: u64) -> Transaction {
        Transaction {
            from: "alice".to_string(),
            to: "bob".to_string(),
            amount,
            fee,
            nonce,
        }
    }

    #[test]
    fn applies_transfer_and_collects_fee() {
        let mut accounts = HashMap::new();
        accounts.insert("alice".to_string(), Account { balance: 100, nonce: 0 });
        let mut fees = 0;
        assert!(apply_transaction(&mut accounts, &mut fees, &tx(0, 25, 2)).is_ok());
        assert_eq!(accounts.get("alice").unwrap().balance, 73);
        assert_eq!(accounts.get("alice").unwrap().nonce, 1);
        assert_eq!(accounts.get("bob").unwrap().balance, 25);
        assert_eq!(fees, 2);
    }

    #[test]
    fn rejects_bad_nonce_without_mutating_accounts() {
        let mut accounts = HashMap::new();
        accounts.insert("alice".to_string(), Account { balance: 100, nonce: 4 });
        let before = accounts.clone();
        let mut fees = 0;
        assert!(apply_transaction(&mut accounts, &mut fees, &tx(5, 10, 2)).is_err());
        assert_eq!(accounts, before);
        assert_eq!(fees, 0);
    }

    #[test]
    fn rejects_insufficient_funds() {
        let mut accounts = HashMap::new();
        accounts.insert("alice".to_string(), Account { balance: 10, nonce: 0 });
        let mut fees = 0;
        assert!(apply_transaction(&mut accounts, &mut fees, &tx(0, 10, 2)).is_err());
        assert!(!accounts.contains_key("bob"));
        assert_eq!(fees, 0);
    }
}
